// // This module converts a 4-bit Gray code input to its corresponding 4-bit binary output.
module verified_bin_to_gray(bin, gray);

    input [3:0] bin;
    output reg [3:0] gray;

    always @(*)
        begin
            gray[3] = bin[3];
            gray[2] = bin[3] ^ bin[2];
            gray[1] = bin[2] ^ bin[1];
            gray[0] = bin[1] ^ bin[0];
        end  

endmodule
